  id: {
    back: '← Kembali ke pusat alat teknik', eyebrow: 'Panduan Teknik', title: 'Panduan Panjang Flange Minimum', subtitle: 'Panduan profesional untuk memahami panjang flange minimum pada bending press brake, tumpuan V-die, kestabilan flange pendek, dan pemilihan tooling.',
    what: { title: 'Apa itu panjang flange minimum?', text: 'Panjang flange minimum adalah kaki tekukan terpendek yang tetap tertumpu secara andal di bahu die bawah saat bending berlangsung. Ini bukan sekadar ukuran gambar; bukaan V, radius dalam, ketebalan, metode bending, dan geometri tooling menentukan kelayakannya. Tanpa tumpuan cukup, flange pendek meluncur ke dalam V dan sudut menjadi tidak stabil.' },
    why: { title: 'Mengapa panjang flange minimum penting', cards: [['Flange pendek tidak stabil', 'Kaki dapat berputar atau bergeser sebelum tekukan terbentuk.'], ['Jatuh ke dalam die', 'Tumpang tindih bahu yang kurang membuat tepi masuk ke V.'], ['Sudut tidak konsisten', 'Perubahan tumpuan merusak repeatability.'], ['Bekas dan interferensi', 'Tekanan lokal atau benturan punch merusak part.'], ['Part ditolak', 'Lokasi dan dimensi akhir salah menjadi scrap.'], ['Produksi berulang', 'Tumpuan tervalidasi menstabilkan setup.']] },
    sections: [['v-opening', 'Hubungan bukaan V dan flange minimum', 'Bukaan V yang lebih besar biasanya memerlukan flange minimum lebih panjang karena jarak bahu die bertambah. V besar menurunkan tonase, tetapi mengurangi dukungan flange pendek dan memperbesar radius alami. V kecil lebih mudah mendukung flange pendek, namun meningkatkan tonase dan risiko bekas.'], ['shoulder', 'Tumpuan bahu die', 'Sebelum bending, flange harus duduk dengan tumpang tindih efektif di atas bahu die. Radius bahu memengaruhi tumpuan dan marking. Bila tumpuan kurang, plat meluncur atau miring; die lebar dapat gagal menahan flange yang sangat pendek.'], ['radius', 'Ketebalan material dan radius dalam', 'Plat lebih tebal umumnya memerlukan V lebih besar dan menghasilkan radius alami lebih besar. Dimensi flange akhir turut dipengaruhi radius serta bend allowance. Flange sangat pendek dapat memerlukan kompensasi proses atau tooling khusus.']],
    materials: { title: 'Pengaruh material', cards: [['Mild steel', 'Acuan awal yang berguna bila ketebalan dan radius dikonfirmasi.'], ['Stainless steel', 'Gaya dan springback lebih besar membuat flange pendek lebih sensitif.'], ['Aluminium', 'Permukaan lunak lebih mudah berubah bentuk atau berbekas di bahu.'], ['Keputusan proses', 'Kekuatan, temper, dan kebutuhan permukaan menentukan kelayakan.']] },
    chart: { title: 'Tabel referensi praktis flange minimum', intro: 'Referensi awal untuk air bending; verifikasi dengan geometri tooling aktual.', headers: ['Ketebalan', 'Rentang V umum', 'Acuan flange minimum', 'Catatan teknik'], rows: [['1.0 mm', '6-8 mm', '5-7 mm', 'Periksa bekas pada permukaan tipis.'], ['1.5 mm', '10-12 mm', '7-9 mm', 'Konfirmasi radius hasil tekuk.'], ['2.0 mm', '12-16 mm', '9-12 mm', 'Butuh dudukan bahu yang jelas.'], ['3.0 mm', '20-24 mm', '14-18 mm', 'Tinjau tonase dan radius.'], ['4.0-6.0 mm', '32-48 mm', '22-34 mm', 'Trial bending disarankan.']], note: 'Nilai ini merupakan referensi teknik. Panjang flange minimum aktual bergantung pada geometri tooling, kondisi material, dan metode bending.' },
    problems: { title: 'Masalah umum bending flange pendek', cards: [['Flange meluncur ke V', 'Tumpuan di bahu tidak cukup.'], ['Sudut tidak stabil', 'Benda kerja bergeser saat forming.'], ['Bekas die berlebih', 'Die sempit memusatkan tekanan.'], ['Retak dekat garis tekuk', 'Radius atau kondisi material terlalu berat.'], ['Interferensi punch', 'Geometri berbenturan sebelum sudut tercapai.'], ['Bukaan V salah', 'Pemilihan tidak mengecek tumpuan.'], ['Dimensi akhir salah', 'Radius dan bend allowance terlewat.']] },
    solutions: { title: 'Solusi tooling untuk flange pendek', intro: 'Tooling standar tidak menyelesaikan semua kondisi flange pendek. Validasi beban dan clearance sebelum produksi.', items: ['Pilih V-die lebih sempit bila tonase, radius, dan permukaan memungkinkan.', 'Gunakan acute tooling atau punch khusus yang sesuai.', 'Rancang die khusus bila bahu standar tidak memberi tumpuan.', 'Evaluasi offset forming, bending bertahap, atau urutan yang diubah.'] },
    notes: { title: 'Catatan teknik', items: ['Tinjau flange pendek dengan tooling nyata sebelum produksi.', 'Cocokkan ukuran gambar dengan radius dan bend allowance yang memungkinkan.', 'Lakukan trial bending untuk flange yang ketat.', 'Lindungi permukaan komponen kosmetik.', 'Berikan margin lebih besar untuk stainless tebal dengan flange pendek.'] },
    faqTitle: 'Pertanyaan yang sering diajukan', faq: [['Apa itu panjang flange minimum?', 'Kaki tekukan terpendek yang dapat ditumpu dengan andal pada bahu die selama bending.'], ['Mengapa bukaan V memengaruhi flange minimum?', 'Bukaan lebih lebar menjauhkan bahu sehingga tumpuan kaki pendek berkurang.'], ['Apa yang terjadi jika flange terlalu pendek?', 'Flange dapat jatuh, menggeser garis tekuk, atau menghasilkan sudut yang tidak berulang.'], ['Bisakah bending lebih pendek dari aturan umum?', 'Kadang bisa dengan tooling khusus tervalidasi dan trial bending.'], ['Bagaimana menekuk flange pendek?', 'Periksa V sempit yang kompatibel, lalu tooling khusus atau urutan alternatif.'], ['Apakah material berpengaruh?', 'Ya; kekuatan, springback, daktilitas, dan permukaan mengubah margin yang dibutuhkan.'], ['Mengapa flange jatuh ke die?', 'Tepi tidak cukup bertumpu di bahu untuk menahan geseran akibat punch.']],
    relatedTitle: 'Alat teknik terkait', relatedAria: 'Alat teknik terkait', relatedLabels: { pressBrakeCalculator: 'Kalkulator press brake', materialDatabase: 'Database material', vDieSelectionTool: 'Alat pemilihan V-die', insideRadiusGuide: 'Panduan radius dalam', springbackDatabase: 'Database springback', bendAllowanceCalculator: 'Kalkulator bend allowance', bendDeductionGuide: 'Panduan Bend Deduction', airBendingGuide: 'Panduan tekuk udara', pressBrakeTonnageGuide: 'Panduan tonase press brake', vDieOpeningGuide: 'Pemilihan bukaan cetakan V', minimumFlangeLengthGuide: 'Panduan Panjang Flange Minimum', toolingSelectionGuide: 'Panduan pemilihan perkakas', crowningGuide: 'Panduan kompensasi lendutan', stainlessSteelBendingGuide: 'Panduan Tekuk Stainless Steel', aluminumBendingGuide: 'Panduan Tekuk Aluminium' },
    diagram: { eyebrow: 'Visualisasi teknik', title: 'Sistem visualisasi flange minimum', svgTitle: 'Perbandingan tumpuan flange minimum', svgDescription: 'Flange pendek yang jatuh ke V-die dibanding flange tertumpu benar beserta dimensi tooling.', instability: 'Flange pendek tidak stabil', supportTitle: 'Tumpuan flange stabil', insufficient: 'tumpuan kurang', slips: 'flange masuk ke die', shortRisk: 'risiko flange pendek', unstable: 'bending tidak stabil', proper: 'tumpuan benar', shoulder: 'tumpuan bahu die', correct: 'panjang flange benar', stable: 'bending stabil', geometry: 'GEOMETRI DAN TUMPUAN', vOpening: 'bukaan V', flangeLength: 'panjang flange', insideRadius: 'radius dalam', punch: 'Punch', sheet: 'Plat', vDie: 'V-die' },
  },
