function createStructuredData() {
  const page = content.en
  return { '@context': 'https://schema.org', '@graph': [
    { '@type': 'WebPage', name: page.title, description: page.seoDescription, url: getSiteUrl(routePath), isPartOf: { '@type': 'WebSite', name: 'ZYCO Engineering Hub', url: getSiteUrl('/engineering-tools') } },
    { '@type': 'TechArticle', headline: page.title, description: page.seoDescription, author: { '@type': 'Organization', name: 'ZYCO' }, publisher: { '@type': 'Organization', name: 'ZYCO', url: getSiteUrl('/') }, mainEntityOfPage: getSiteUrl(routePath) },
    { '@type': 'FAQPage', mainEntity: page.faq.map(([question, answer]) => ({ '@type': 'Question', name: question, acceptedAnswer: { '@type': 'Answer', text: answer } })) },
  ] }
}

function Card({ title, text }) { return <article className='zyco-flange__card'><h3>{title}</h3><p>{text}</p></article> }

